## Confirm endpoint example

```ts
import crypto from "node:crypto";
import bcrypt from "bcrypt";

async function confirmPasswordReset(req, res) {
  const token = String(req.body.token || "");
  const newPassword = String(req.body.newPassword || "");

  if (!token || newPassword.length < 12) {
    return res.status(400).json({ error: "Invalid request" });
  }

  const tokenHash = crypto.createHash("sha256").update(token).digest("hex");

  const resetRecord = await db.passwordResetTokens.findValidByHash(tokenHash);
  if (!resetRecord) {
    return res.status(400).json({ error: "Invalid or expired token" });
  }

  const passwordHash = await bcrypt.hash(newPassword, 12);

  await db.transaction(async (tx) => {
    await tx.users.updatePassword(resetRecord.user_id, passwordHash);
    await tx.passwordResetTokens.markConsumed(resetRecord.id);
    await tx.sessions.revokeAllForUser(resetRecord.user_id);
    await tx.auditLogs.insert({
      user_id: resetRecord.user_id,
      event_type: "password_reset_completed"
    });
  });

  return res.status(200).json({ success: true });
}
```

