## 3) Wire the endpoint

Example using Express + TypeScript:

```ts
// routes/productSearch.ts
import { Router } from 'express';
import { typesense } from '../lib/typesense';

const router = Router();

router.get('/product-search', async (req, res) => {
  try {
    const {
      q = '*',
      page = '1',
      per_page = '20',
      category,
      min_price,
      max_price,
      in_stock,
      lat,
      lng,
      radius_km,
      sort,
    } = req.query as Record<string, string>;

    const filters: string[] = [];

    if (category) {
      filters.push(`category:=${category}`);
    }

    if (min_price) {
      filters.push(`price:>=${Number(min_price)}`);
    }

    if (max_price) {
      filters.push(`price:<=${Number(max_price)}`);
    }

    if (in_stock !== undefined) {
      filters.push(`in_stock:=${in_stock === 'true'}`);
    }

    if (lat && lng && radius_km) {
      filters.push(`location:(${lat}, ${lng}, ${radius_km} km)`);
    }

    const searchParameters: Record<string, any> = {
      q,
      query_by: 'name,brand,category,description',
      page: Number(page),
      per_page: Math.min(Number(per_page), 100),
      filter_by: filters.length ? filters.join(' && ') : undefined,
      sort_by: buildSort(sort, lat, lng),
      include_fields: 'id,name,slug,brand,category,price,image_url,in_stock',
    };

    const result = await typesense
      .collections('products')
      .documents()
      .search(searchParameters);

    res.json({
      found: result.found,
      page: result.page,
      hits: (result.hits || []).map((hit: any) => hit.document),
    });
  } catch (error: any) {
    console.error('Product search failed', error);
    res.status(500).json({
      error: 'Search failed',
      details: error?.message,
    });
  }
});

function buildSort(sort?: string, lat?: string, lng?: string) {
  switch (sort) {
    case 'price_asc':
      return 'price:asc,_text_match:desc';
    case 'price_desc':
      return 'price:desc,_text_match:desc';
    case 'popular':
      return 'popularity:desc,_text_match:desc';
    case 'nearest':
      if (lat && lng) {
        return `location(${lat}, ${lng}):asc,_text_match:desc`;
      }
      return '_text_match:desc';
    default:
      return '_text_match:desc,popularity:desc';
  }
}

export default router;
```

