### 3) Product-search endpoint

Example with Express + TypeScript:

```ts
// routes/productSearch.ts
import { Router } from 'express';
import { typesense } from '../lib/typesense';

const router = Router();

router.get('/product-search', async (req, res) => {
  try {
    const {
      q = '',
      page = '1',
      per_page = '20',
      category,
      brand,
      min_price,
      max_price,
      in_stock,
      sort,
      lat,
      lng,
      radius_km,
    } = req.query as Record<string, string>;

    const filters: string[] = [];

    if (category) filters.push(`category:=[${category}]`);
    if (brand) filters.push(`brand:=[${brand}]`);
    if (in_stock === 'true') filters.push(`in_stock:=true`);
    if (in_stock === 'false') filters.push(`in_stock:=false`);
    if (min_price) filters.push(`price:>=${Number(min_price)}`);
    if (max_price) filters.push(`price:<=${Number(max_price)}`);

    if (lat && lng && radius_km) {
      filters.push(`location:(${lat}, ${lng}, ${Number(radius_km)} km)`);
    }

    let sort_by = 'popularity:desc';

    if (sort === 'price_asc') sort_by = 'price:asc';
    else if (sort === 'price_desc') sort_by = 'price:desc';
    else if (sort === 'newest') sort_by = 'created_at:desc';
    else if (sort === 'relevance') sort_by = '_text_match:desc,popularity:desc';

    const searchParameters = {
      q: q || '*',
      query_by: 'name,description,brand,category',
      page: Number(page),
      per_page: Number(per_page),
      filter_by: filters.join(' && ') || undefined,
      sort_by,
      num_typos: 2,
      prioritize_exact_match: true,
      facet_by: 'category,brand,in_stock',
    };

    const result = await typesense
      .collections('products')
      .documents()
      .search(searchParameters);

    res.json({
      found: result.found,
      page: result.page,
      hits: result.hits?.map((hit: any) => hit.document) ?? [],
      facets: result.facet_counts ?? [],
    });
  } catch (error: any) {
    console.error('product-search failed', error);
    res.status(500).json({
      error: 'Search failed',
      details: error?.message,
    });
  }
});

export default router;
```

