## 4) Wire the endpoint

Example in **Express + TypeScript**:

```ts
// routes/productSearch.ts
import { Router } from 'express';
import { typesense } from '../lib/typesense';

const router = Router();

router.get('/product-search', async (req, res) => {
  try {
    const {
      q = '',
      page = '1',
      per_page = '20',
      category,
      in_stock,
      min_price,
      max_price,
      lat,
      lng,
      radius_km,
      sort,
    } = req.query as Record<string, string>;

    const filterParts: string[] = [];

    if (category) {
      filterParts.push(`category:=${category}`);
    }

    if (in_stock === 'true') {
      filterParts.push('in_stock:=true');
    } else if (in_stock === 'false') {
      filterParts.push('in_stock:=false');
    }

    if (min_price || max_price) {
      const min = min_price ?? '0';
      const max = max_price ?? '999999999';
      filterParts.push(`price:[${min}..${max}]`);
    }

    // Geo-spatial filter
    if (lat && lng && radius_km) {
      filterParts.push(`location:(${lat}, ${lng}, ${radius_km} km)`);
    }

    let sort_by = 'popularity:desc';

    if (sort === 'price_asc') sort_by = 'price:asc';
    if (sort === 'price_desc') sort_by = 'price:desc';
    if (sort === 'newest') sort_by = 'popularity:desc'; // swap for created_at if indexed

    const searchParameters = {
      q: q || '*',
      query_by: 'name,brand,category,description',
      page: Number(page),
      per_page: Number(per_page),
      filter_by: filterParts.join(' && '),
      sort_by,
      num_typos: 2,
      prioritize_exact_match: true,
      typo_tokens_threshold: 1,
      facet_by: 'category,in_stock',
      max_facet_values: 20,
    };

    const result = await typesense
      .collections('products')
      .documents()
      .search(searchParameters);

    res.json({
      found: result.found,
      page: result.page,
      hits: result.hits?.map((hit: any) => ({
        score: hit.text_match,
        ...hit.document,
      })) ?? [],
      facet_counts: result.facet_counts ?? [],
    });
  } catch (error: any) {
    console.error('Product search failed:', error);
    res.status(500).json({
      error: 'Search request failed',
      details: error?.message || 'Unknown error',
    });
  }
});

export default router;
```

